#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long *f = (long long*)malloc((N+1)*sizeof(long long));
        for(int i=1;i<=N;i++) scanf("%lld",&f[i]);
        long long fuel = f[1];
        long long dist = 0;
        for(int i=2;i<=N;i++){
            long long need = (i-1) - dist;
            if(fuel >= need){
                fuel -= need;
                dist += need;
                fuel += f[i];
            }else{
                dist += fuel;
                fuel = 0;
                break;
            }
        }
        dist += fuel; // use remaining fuel
        printf("%lld\n", dist);
        free(f);
    }
    return 0;
}

